data.text:
@charset "utf-8";
img {
  width: 100%;
}
/* tabs */
.bg-opac-blue {
  background: rgba(44, 111, 183, 0.1);
}
.tabs {
  border-bottom: 1px solid #e7e8ec;
  height: 40px;
  position: relative;
}
.tabs ul,
.tabs li {
  list-style-type: none;
  -webkit-margin-before: 0;
  -webkit-margin-after: 0;
  -webkit-margin-start: 0px;
  -webkit-margin-end: 0px;
  -webkit-padding-start: 0;
}
.tabs li {
  float: left;
  padding: 10px 20px 8px;
  margin-right: 8px;
  cursor: pointer;
  background-color: #fafafa;
  border: 1px solid #e7e8ec;
  border-radius: 2px 2px 0 0;
  border-bottom: 0;
  color: #102247;
}
.tabs li:hover {
  color: #5c8ae6;
}
.tabs li.cur {
  height: 40px;
}
.lightning-con {
  border: 1px solid #e7e8ec;
  border-top: 0;
}
/* tabs end */

.charts-box-auto,
.hotel-university,
.columns-pic {
  overflow: auto;
  width: 100%;
  margin-bottom: 20px;
}
.charts-content,
.answer-box {
  min-width: 900px;
}
.columns-pic {
  margin-bottom: 0;
}
/* ==== */
.mb20 {
  margin-bottom: 10px !important;
}
.txt18.pb10,
.txt18.pb5 {
  font-size: 16px;
  font-weight: bold;
  padding-bottom: 10px;
  position: relative;
}
.txt18.pb10 > span,
.txt18.pb5 > span {
  font-weight: 400;
}
.tags-blue {
  background: #597ee6;
}
.tags-org {
  background: #e97849;
}
.ib-vm,
.ib-vb,
.ib-vt {
  display: inline-block;
  *display: inline;
  *zoom: 1;
  vertical-align: middle;
}
.ib-vb {
  vertical-align: bottom;
}
.ib-vt {
  vertical-align: top;
}
.ellipsis {
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  word-break: break-word;
}
.line2-ellipsis {
  white-space: normal;
  -webkit-line-clamp: 2;
  display: -webkit-box;
  -webkit-box-orient: vertical;
  overflow: hidden;
  word-break: break-word;
}
.line3-ellipsis {
  white-space: normal;
  -webkit-line-clamp: 3;
  display: -webkit-box;
  -webkit-box-orient: vertical;
  overflow: hidden;
  word-break: break-word;
}
.bor0 {
  border: 0 !important;
}
.bor {
  border: #e7e8ec solid 1px !important;
  border-radius: 4px;
}
.small {
  font-weight: 400;
}

.df {
  display: -webkit-box;
  display: -webkit-flex;
  display: flex;
}
.fx1 {
  -webkit-box-flex: 1;
  -webkit-flex: 1;
  flex: 1;
}
.ebk-col-3,
.ebk-col-4,
.ebk-col-6,
.ebk-col-7 {
  float: left;
}
.ebk-col-3 {
  width: 30%;
}
.ebk-col-4 {
  width: 40%;
}
.ebk-col-6 {
  width: 60%;
}
.ebk-col-7 {
  width: 70%;
}
.ebk-w-5 {
}
.ebk-w-5 > .fl {
  width: 49%;
  margin-right: 2%;
}
.ebk-w-5 > .fr {
  width: 49%;
}
.ebk-w-5 > .f-w-10 {
  width: 100%;
  float: left;
}
.ebk-w-5 > .sales-show {
  margin-bottom: 20px;
}
.panel {
  border-color: #e7e8ec;
}
.position-v {
  position: relative;
}
.position-v .btn {
  position: absolute;
  right: 0;
  top: 8px;
  color: #102247;
}
.position-v .btn:hover {
  color: #5c8ae6;
}
.position-v .btn .icon-download {
  font-size: 16px;
  margin-right: 2px;
}
.icon-head {
  background: url(//pic.c-ctrip.com/ebooking/intebk/date_head.png) no-repeat;
  width: 152px;
  height: 152px;
  display: inline-block;
  *display: inline;
  *zoom: 1;
  vertical-align: middle;
}
.icon-date {
  background: url(//pic.c-ctrip.com/ebooking/intebk/icon_date.png) no-repeat;
  display: inline-block;
  *display: inline;
  *zoom: 1;
  vertical-align: middle;
}
.icon-rooms-show1 {
  width: 122px;
  height: 122px;
  background-position: -2px -1px;
}
.icon-rooms-show2 {
  width: 122px;
  height: 122px;
  background-position: -141px -1px;
}
.icon-rooms-show3 {
  width: 115px;
  height: 115px;
  background-position: -280px -1px;
}
.num1 {
  width: 24px;
  height: 24px;
  background-position: -1px -128px;
}
.num2 {
  width: 24px;
  height: 24px;
  background-position: -1px -156px;
}
.num3 {
  width: 24px;
  height: 24px;
  background-position: -1px -185px;
}
.icon-syt {
  background-position: -32px -128px;
  width: 26px;
  height: 30px;
}
.icon-comments {
  background-position: -32px -165px;
  width: 30px;
  height: 31px;
}
.icon-price {
  background-position: -71px -131px;
  width: 27px;
  height: 27px;
}
.icon-imgs {
  background-position: -68px -164px;
  width: 31px;
  height: 32px;
}
.icon-finish {
  width: 42px;
  height: 42px;
  background-position: -105px -129px;
}
.icon-light {
  width: 12px;
  height: 18px;
  background-position: -38px -202px;
}
.ebk-icons {
  background: url(//pic.c-ctrip.com/ebooking/intebk/hmll-sprite.png) no-repeat;
  display: inline-block;
  *display: inline;
  *zoom: 1;
  vertical-align: middle;
  width: 28px;
  height: 28px;
}
.icon-bor-success {
  background-position: 0 0;
}

/* 经营数据 */
.ebk3-tabs-group .group-tabs {
  padding: 7px 10px !important;
}
.debuff {
  white-space: nowrap;
  overflow: auto;
  padding: 15px 5px;
}
.debuff li {
  width: 400px;
  height: 150px;
  border: 1px solid #e7e8ec;
  border-radius: 4px;
  font-size: 14px;
  padding: 15px 20px;
  white-space: normal;
  display: inline-block;
  *display: inline;
  *zoom: 1;
  vertical-align: middle;
  margin-right: 10px;
}
.debuff li > p {
  padding-right: 80px;
}
.debuff-hd {
  margin-bottom: 8px;
}
.remarks > .hd {
  color: #566980;
  margin-right: 10px;
}
.real-list-box {
  border-color: #ddd;
  padding: 20px 0;
  overflow: auto;
  white-space: nowrap;
}
.real-list {
  padding: 0 20px;
  border-right: 1px solid #e7e8ec;
  display: inline-block;
  vertical-align: top;
  white-space: normal;
  width: 33%;
  min-width: 380px;
}
.real-list:last-child {
  border-right: 0;
}
.real-list .date-box {
  width: 150px;
  float: right;
  padding: 0 30px 0 0;
}
.real-list .date-box:before {
  top: 4px;
  right: 6px;
}
.real-list .form-control {
  height: 26px;
  line-height: 26px;
  width: 100%;
}
.num-value {
  position: relative;
}
.num-value > p {
  color: #566980;
}
.num-value > span.txt42 {
  font-weight: 700;
  line-height: 1;
  font-size: 28px;
}
.alert-light {
  background: #e0eaf4;
  border-radius: 4px;
  padding: 3px 100px 3px 30px;
  position: relative;
}
.alert-light .icon-light {
  margin-left: -20px;
}
.alear-update {
  position: absolute;
  right: 20px;
  top: 3px;
}

.name-room {
  position: absolute;
  right: 0;
  top: 0;
  width: 45%;
}
.tab-handover {
  border-color: #ddd;
}
.tab-handover .tab-content {
  float: left;
}
.tab-handover .ebk-nav-flat {
  padding-bottom: 0;
  border-bottom: 0;
  margin-bottom: 0;
}
.core-date-li .core-date-list {
  width: 50%;
}
.core-date-list {
  float: left;
  width: 33%;
}
.tab-handover li {
  border-radius: 4px 4px 0 0;
  min-height: 150px;
  cursor: pointer;
  border-bottom: #ddd solid 1px;
  margin-right: 0;
  width: 60%;
  padding: 20px;
  overflow: hidden;
  padding-bottom: 20px;
}
.tab-handover li.active {
  border-bottom: #fff solid 1px;
  background: #ffffff;
  box-shadow: inset 0 2px 0 0 #2c6fb7;
}
.tab-handover .core-date-li,
.title-w {
  width: 40%;
}
.title-w2 {
  width: 60%;
}
.core-date-list .num-value {
  margin: 10px 0;
}
.ebk-nav-flat > li > a {
  color: #102247;
}
.ebk-nav-flat > li > a:hover {
  color: #5c8ae6;
}
.ebk-nav-flat .active a {
  font-weight: 400;
  cursor: pointer;
}
.tab-handover .active a,
.tab-handover .ebk-nav-flat a:hover {
  color: #333;
  border: 0;
}

.core-analytics,
.real-analytics {
  padding: 0 20px;
}
.flow-bar {
  overflow: auto;
  margin-bottom: 20px;
}
.group-tabs {
  padding: 5px 10px;
}
.group-tabs:hover {
  color: #5c8ae6;
}

.market-chart-pic {
  font-size: 18px;
  color: #566980;
  padding: 20px 0;
  overflow: hidden;
  clear: both;
}
.market-chart-pic li {
  float: left;
  width: 50%;
  text-align: center;
}
.market-chart-pic i {
  width: 8px;
  height: 8px;
  margin-right: 5px;
  border-radius: 50%;
  display: inline-block;
  *display: inline;
  *zoom: 1;
  font-style: normal;
}
.market-chart-pic strong {
  display: block;
  font-size: 42px;
  color: #102647;
}
.chart-pic {
  position: relative;
}
.chart-pic .table {
  min-width: 800px;
  border-bottom: 1px solid #e7e8ec;
}
.chart-pic .table td,
.chart-pic .table th {
  color: #566980;
  height: 60px;
  width: 120px;
  font-weight: 400;
  text-align: center;
}
.chart-pic .table td {
  height: 41px;
}
.chart-pic .table-responsive {
  padding-left: 200px;
}
.chart-tab-hd.table {
  position: absolute;
  left: 0;
  width: 200px;
  top: 0;
  z-index: 10;
  background: #fff;
  min-width: 200px;
  box-shadow: 2px 2px 5px 0px rgba(0, 0, 0, 0.1);
}
.chart-tab-hd.table .ellipsis {
  width: 160px;
  height: 20px;
}
.chart-tab-bd.table th {
  text-align: right;
}
.room-state,
.room-nums {
  background: #f2f2f2;
  border: 1px solid #e7e8ec;
  border-radius: 10px;
  width: 110px;
  text-align: right;
  height: 18px;
  padding: 0 10px;
  line-height: 18px;
}
.room-nums.empty-room {
  color: #c3c9d0;
}
.room-state {
  background: rgba(71, 178, 103, 0.8);
  border: 0;
  font-size: 0;
}
.room-state.full-room {
  background: rgba(255, 80, 77, 0.6);
}

.fliter-box .date-box {
  padding: 0 30px 0 0;
}
.fliter-box .date-box:before {
  top: 10px;
  right: 7px;
}

.sales-show {
  border-color: #e7e8ec;
  margin-bottom: 0;
  white-space: nowrap;
  overflow: auto;
  min-height: 135px;
}
.sales-show .ebk-nav-flat {
  margin-bottom: 0;
  border-bottom: 0;
  width: 100%;
  display: -webkit-box;
  display: -webkit-flex;
  display: flex;
}
.sales-show li {
  padding: 20px;
  margin-right: 0;
  -webkit-box-flex: 1;
  -webkit-flex: 1;
  flex: 1;
}
.sales-show .core-date-list {
  border-right: 1px solid #ebebeb;
  width: 100%;
  padding: 5px 20px;
}
.sales-show li:last-child .core-date-list {
  border-right: 0;
}
.columns-pic::-webkit-scrollbar-thumb,
.flow-bar::-webkit-scrollbar-thumb,
.keyword-box::-webkit-scrollbar-thumb,
.resolvent-box::-webkit-scrollbar-thumb,
.bill-board::-webkit-scrollbar-thumb,
.hots-analysis::-webkit-scrollbar-thumb,
.sales-show::-webkit-scrollbar-thumb {
  -webkit-border-radius: 8px;
  outline: 2px solid #cad2d6;
  background-color: #d8dde3;
  -webkit-box-shadow: inset 0 0 2px rgba(0, 0, 0, 0.05);
  outline-offset: -2px;
}
.columns-pic::-webkit-scrollbar-thumb:hover,
.flow-bar::-webkit-scrollbar-thumb:hover,
.keyword-box::-webkit-scrollbar-thumb:hover,
.resolvent-box::-webkit-scrollbar-thumb:hover,
.bill-board::-webkit-scrollbar-thumb:hover,
.hots-analysis::-webkit-scrollbar-thumb:hover,
.sales-show::-webkit-scrollbar-thumb:hover {
  -webkit-border-radius: 8px;
  background-color: #747a80;
}
.columns-pic::-webkit-scrollbar,
.flow-bar::-webkit-scrollbar,
.keyword-box::-webkit-scrollbar,
.resolvent-box::-webkit-scrollbar,
.bill-board::-webkit-scrollbar,
.hots-analysis::-webkit-scrollbar,
.sales-show::-webkit-scrollbar {
  width: 10px;
  height: 8px;
}
.columns-pic::-webkit-scrollbar-track-piece,
.flow-bar::-webkit-scrollbar-track-piece,
.keyword-box::-webkit-scrollbar-track-piece,
.resolvent-box::-webkit-scrollbar-track-piece,
.bill-board::-webkit-scrollbar-track-piece,
.hots-analysis::-webkit-scrollbar-track-piece,
.sales-show::-webkit-scrollbar-track-piece {
  -webkit-border-radius: 0;
  background-color: transparent;
}

.tabs {
  border-bottom-right-radius: 4px;
}
.tab-ctrip-qu {
  padding: 20px;
  border: #e7e8ec solid 1px;
  border-top: 0;
  border-radius: 4px;
}
.tab-ctrip-qu1 {
  padding: 20px;
  border-radius: 4px;
  padding-top: 50px;
}
.hotel-state,
.rooms-solution {
}
.hotel-state {
  margin-top: 12px;
}
.d-sort-arrows.gray-arrows:before {
  color: #999;
  border-color: transparent transparent #999;
}
.hotel-state .table-condition {
  overflow: auto;
}
.table-condition > .table {
  margin-bottom: 0;
}
/* .table-condition .table{margin-bottom: 0;min-width: 900px;} */
.date-sources-box .table-condition .table {
  min-width: 400px;
  margin-bottom: 0;
}
.table-condition {
  border-bottom: #e7e8ec solid 1px;
}
.rooms-solution ul {
  padding: 20px 7px 20px 15px;
}
.rooms-solution li {
  float: left;
  width: 32%;
  padding: 20px 20px 20px 150px;
  border-radius: 4px;
  margin-right: 25px;
  box-sizing: border-box;
}
.rooms-solution li:last-child {
  margin-right: 0;
}
.rooms-solution .icon-date {
  float: left;
  margin-left: -135px;
}
.solution-li1 {
  background: #edf5ff;
}
.solution-li2 {
  background: #fff5f5;
}
.solution-li3 {
  background: #fff2ff;
}

.hot-rooms .panel {
  border-color: #e7e8ec;
  padding: 20px;
  margin-bottom: 20px;
}
.rooms-img {
  padding-bottom: 5px;
  overflow: auto;
  margin-bottom: 15px;
}
.rooms-img > ul {
  white-space: nowrap;
  min-width: 1000px;
}
.rooms-img li {
  width: 300px;
  height: 160px;
  margin-right: 20px;
  border-radius: 4px;
  overflow: hidden;
}
.rooms-img li > img {
  width: 100%;
  height: 100%;
}
.hot-rooms .table th {
  font-weight: 400;
}
.rooms-img.mb5 {
  margin-bottom: 5px;
}
.hot-rooms .alert-light {
  min-width: 625px;
}
.hot-rooms .table-condition .table {
  min-width: 900px;
}

.select-max.dropdown .btn {
  border-radius: 2px;
  min-height: 40px;
  min-width: 180px;
}

.tab-handover li.active,
.tab-handover li:hover {
  border: #5c8ae6 solid 1px;
  border-bottom: transparent solid 1px;
  background: #fff;
  box-shadow: inset 0 2px 0 0 #5c8ae6;
}
.tab-handover .core-date-li,
.title-w {
  width: 40%;
}
.core-analytics,
.real-analytics {
  padding: 20px 20px 0;
  box-shadow: inset 0 2px 0 0 #5c8ae6;
  border: #5c8ae6 solid 1px;
  border-top: 0;
}
/* 经营数据 end */

/* market analysis start */
.serch-roomid {
  padding: 15px 0;
  overflow: hidden;
}
.serch-roomid .choose-input {
  padding: 3px 5px 3px 25px;
  margin-top: -5px;
  border: #e7e8ec solid 1px;
  border-radius: 4px;
  float: right;
}
.serch-roomid .choose-input .ebk-ico-magnifier {
  right: auto;
  left: 4px;
  top: 5px;
}
.serch-roomid .choose-input > input:focus {
  outline: none;
}
.product-list {
  padding: 0 20px 12px;
  border: #e7e8ec solid 1px;
  border-radius: 4px;
  overflow: auto;
}

.product-list li {
  padding: 10px 90px 10px 150px;
  overflow: hidden;
  position: relative;
  box-shadow: inset 0 -1px 0 0 #e7e8ec;
}
.product-pic {
  float: left;
  margin-left: -150px;
  width: 140px;
  height: 108px;
  border-radius: 4px;
  overflow: hidden;
}
.product-pic > img {
  width: 100%;
  height: 100%;
  border: 0;
}
.product-list .title,
.product-list .address {
  width: 50%;
}
.min-space {
  min-height: 25px;
}
.address {
  line-height: 1;
  color: #c3c9d0;
  font-size: 14px;
}
.add-btn {
  position: absolute;
  right: 20px;
  top: 50%;
  width: 89px;
  margin-top: -13px;
}
.add-btn .btn {
  width: 100%;
}
.user-analysis {
  position: absolute;
  right: 110px;
  top: 20px;
}
.user-analysis > div {
  margin: 0 20px;
  padding: 15px;
}
.user-analysis .hotel-fit {
  background: #e9f0f7;
  border-radius: 8px;
}
.hotel-fit.txt24 {
  color: #2c6fb7;
}
.flow-ul li {
  overflow: hidden;
  padding: 16px;
  /*box-shadow:2px 3px 8px 5px rgba(44,111,183,0.20);*/
  border: 1px solid #e7e8ec;
  border-radius: 4px;
}
.anslysis-result-box {
  margin-bottom: 20px;
}
.anslysis-result-box .ebk-col-4 {
  padding-right: 20px;
}
.analysis-list .core-date-list {
  width: 25%;
}
.resolvent-box {
  margin-bottom: 20px;
  overflow: auto;
  white-space: nowrap;
}
.resolvent-box .ebk-col-3 {
  width: 400px;
  padding-bottom: 10px;
  display: inline-block;
  vertical-align: top;
  float: none;
}
.resolvent-box .ebk-col-7 {
  padding-bottom: 10px;
  display: inline-block;
  vertical-align: top;
  float: none;
  width: calc(100% - 425px);
}
.means-list1 {
  padding-right: 20px;
}
.means-list1 li,
.means-list2 li {
  position: relative;
  min-height: 160px;
  display: inline-block;
  vertical-align: top;
  padding: 10px 20px 40px;
  border-radius: 4px;
  box-shadow: 2px 3px 8px 5px rgba(44, 111, 183, 0.2);
  min-width: 260px;
}
.means-list2 li {
  width: 390px;
  margin-right: 20px;
}
.means-list2 li:last-child {
  margin-right: 0;
}
.means-hd {
  background-image: linear-gradient(225deg, #ffe172 0%, #f7a21c 100%);
  border-radius: 4px;
  color: #fff;
  padding: 12px 20px;
  font-size: 16px;
  margin-bottom: 10px;
}
.click-tools {
  position: absolute;
  right: 20px;
  bottom: 15px;
}
.app-li-date,
.app-li-charts {
  border: #e7e8ec solid 1px;
}
.app-li-charts {
  border-top-left-radius: 4px;
  border-top-right-radius: 4px;
  border-bottom: 0;
  overflow: auto;
}
.app-li-date {
  border-bottom-left-radius: 4px;
  border-bottom-right-radius: 4px;
  overflow: auto;
}

.value-progress-box {
  padding: 20px 20px 20px 120px;
  position: relative;
  min-width: 1205px;
  overflow: auto;
}
.value-progress-list {
  margin-bottom: 26px;
}
.left-ps {
  float: left;
  margin-left: -95px;
  width: 95px;
  text-align: right;
  font-size: 14px;
  color: #566980;
  margin-top: 8px;
}
.value-progress-ing {
  padding-left: 80px;
  width: 600px;
}
.value1-bar,
.value2-bar {
  margin-left: 60px;
  position: relative;
  margin: 3px 0;
}
.value1,
.value2 {
  font-size: 14px;
  color: #102647;
  font-weight: bold;
  position: absolute;
  left: -60px;
  line-height: 36px;
}
.value2 {
  color: #566980;
  font-weight: 400;
  line-height: 16px;
}
.value1-bar {
  background: #2c6fb7;
  height: 36px;
  width: 100%;
