        "/api/inland/marketanalysis/flowanalysis/queryFlowTransforNewV1" +
        q;

      setWebSpiderRequestnew(
        JSON.stringify(comParamTrans),
        function (webSpiderRequest) {
          if (settled) {
            return;
          }
          var custom = Object.assign({}, comParamTrans, webSpiderRequest);
          fetch(transUrl, {
            method: "POST",
            headers: { "Content-Type": "application/json;" },
            body: JSON.stringify(custom),
            credentials: "same-origin",
          })
            .then(function (r) {
              return r.ok ? r.json() : null;
            })
            .then(function (json) {
              if (!settled) {
                settled = true;
                clearTimeout(timer);
                resolve(json);
              }
            })
            .catch(function () {
              if (!settled) {
                settled = true;
                clearTimeout(timer);
                resolve(null);
              }
            });
        },
      );
    });

    store.scanPrefetchPromise = scanPromise;
    store.transPrefetchPromise = transPromise;
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", runPrefetch);
  } else {
    setTimeout(runPrefetch, 0);
  }
})();

